38	// EffectiveNginxProxy holds the result of merging the NginxProxySpec on this resource with the NginxProxySpec on the
39	// GatewayClass resource. This is the effective set of config that should be applied to the Gateway.
40	type EffectiveNginxProxy ngfAPIv1alpha2.NginxProxySpec
