42	// buildEffectiveNginxProxy builds the effective NginxProxy for the Gateway by merging the GatewayClass and Gateway
43	// NginxProxy resources. Fields specified on the Gateway NginxProxy override those set on the GatewayClass NginxProxy.
44	func buildEffectiveNginxProxy(gatewayClassNp, gatewayNp *NginxProxy) *EffectiveNginxProxy {
45		gcNpValid, gwNpValid := nginxProxyValid(gatewayClassNp), nginxProxyValid(gatewayNp)
46		if !gcNpValid && !gwNpValid {
47			return nil
48		}
49	
50		if !gcNpValid {
51			enp := EffectiveNginxProxy(*gatewayNp.Source.Spec.DeepCopy())
52			return &enp
53		}
54	
55		if !gwNpValid {
56			enp := EffectiveNginxProxy(*gatewayClassNp.Source.Spec.DeepCopy())
57			return &enp
58		}
59	
60		gcSpec := EffectiveNginxProxy(*gatewayClassNp.Source.Spec.DeepCopy())
61		global := EffectiveNginxProxy(*gatewayClassNp.Source.Spec.DeepCopy())
62		local := EffectiveNginxProxy(*gatewayNp.Source.Spec.DeepCopy())
63	
64		// by marshaling the local config and then unmarshaling on top of the global config,
65		// we ensure that any unset local values are set with the global values
66		localBytes, err := json.Marshal(local)
67		if err != nil {
68			panic(
69				fmt.Sprintf(
70					"could not marshal NginxProxy resource referenced by Gateway %s",
71					client.ObjectKeyFromObject(gatewayNp.Source),
72				),
73			)
74		}
75	
76		err = json.Unmarshal(localBytes, &global)
77		if err != nil {
78			panic(
79				fmt.Sprintf(
80					"could not unmarshal NginxProxy resource referenced by GatewayClass %s",
81					client.ObjectKeyFromObject(gatewayClassNp.Source),
82				),
83			)
84		}
85	
86		// Clean up the effective configuration by handling slice unsetting and other cases
87		// that are not handled by JSON merging, such as mutual exclusivity between fields.
88		cleanupEffectiveNginxProxy(&local, &global, &gcSpec)
89	
90		return &global
91	}
