93	// cleanupEffectiveNginxProxy handles post-JSON merge cleanup for the effective NginxProxy configuration.
94	// This includes manually unsetting slices and handling mutual exclusion between certain fields.
95	// gcSpec is the pre-merge GatewayClass spec, used to restore sub-fields dropped when a Gateway
96	// partially overrides a nested struct (e.g. sets waf.disableCookieSeed but not waf.enabled).
97	func cleanupEffectiveNginxProxy(local, global, gcSpec *EffectiveNginxProxy) {
98		cleanupTelemetry(local, global)
99		cleanupRewriteClientIP(local, global)
100		cleanupKubernetes(local, global)
101		cleanupWAF(local, global, gcSpec)
102		cleanupCompression(local, global)
103	}
