140	// cleanupWAF restores WAFSpec fields that the Gateway left nil so they inherit from the GatewayClass.
141	// When a Gateway NginxProxy sets the waf object partially (e.g. only disableCookieSeed), the JSON
142	// merge overwrites the entire waf struct in global with the Gateway's value, dropping any sub-fields
143	// the Gateway did not specify. This restores those nil sub-fields from the pre-merge GatewayClass spec.
144	func cleanupWAF(local, global, gcSpec *EffectiveNginxProxy) {
