224	func processNginxProxies(
225		nps map[types.NamespacedName]*ngfAPIv1alpha2.NginxProxy,
226		validator validation.GenericValidator,
227		gc *v1.GatewayClass,
228		gws map[types.NamespacedName]*v1.Gateway,
229		plus bool,
230	) map[types.NamespacedName]*NginxProxy {
231		referencedNginxProxies := make(map[types.NamespacedName]*NginxProxy)
232	
233		if gcReferencesAnyNginxProxy(gc) {
234			// we will ignore references without namespaces
235			// the gateway class status will contain an error message about the missing namespace
236			if gc.Spec.ParametersRef.Namespace != nil {
237				refNp := types.NamespacedName{
238					Name:      gc.Spec.ParametersRef.Name,
239					Namespace: string(*gc.Spec.ParametersRef.Namespace),
240				}
241	
242				if np, ok := nps[refNp]; ok {
243					referencedNginxProxies[refNp] = buildNginxProxy(np, validator, plus)
244				}
245			}
246		}
247	
248		for _, gw := range gws {
249			if gwReferencesAnyNginxProxy(gw) {
250				refNp := types.NamespacedName{
251					Name:      gw.Spec.Infrastructure.ParametersRef.Name,
252					Namespace: gw.Namespace,
253				}
254				if np, ok := nps[refNp]; ok {
255					referencedNginxProxies[refNp] = buildNginxProxy(np, validator, plus)
256				} else {
257					referencedNginxProxies[refNp] = nil
258				}
259			}
260		}
261	
262		if len(referencedNginxProxies) == 0 {
263			return nil
264		}
265	
266		return referencedNginxProxies
267	}
