269	// buildNginxProxy validates and returns the NginxProxy associated with the GatewayClass (if it exists).
270	func buildNginxProxy(
271		np *ngfAPIv1alpha2.NginxProxy,
272		validator validation.GenericValidator,
273		plus bool,
274	) *NginxProxy {
275		if np != nil {
276			errs := validateNginxProxy(validator, np, plus)
277	
278			return &NginxProxy{
279				Source:  np,
280				Valid:   len(errs) == 0,
281				ErrMsgs: errs,
282			}
283		}
284	
285		return nil
286	}
