307	// validateNginxProxy performs re-validation on string values in the case of CRD validation failure.
308	func validateNginxProxy(
309		validator validation.GenericValidator,
310		npCfg *ngfAPIv1alpha2.NginxProxy,
311		plus bool,
312	) field.ErrorList {
313		var allErrs field.ErrorList
314		spec := field.NewPath("spec")
315	
316		telemetry := npCfg.Spec.Telemetry
317		if telemetry != nil {
318			telPath := spec.Child("telemetry")
319			if telemetry.ServiceName != nil {
320				if err := validator.ValidateServiceName(*telemetry.ServiceName); err != nil {
321					allErrs = append(
322						allErrs,
323						field.Invalid(telPath.Child("serviceName"), *telemetry.ServiceName, err.Error()),
324					)
325				}
326			}
327	
328			if telemetry.Exporter != nil {
329				exp := telemetry.Exporter
330				expPath := telPath.Child("exporter")
331	
332				if exp.Endpoint != nil {
333					if err := validator.ValidateEndpoint(*exp.Endpoint); err != nil {
334						allErrs = append(allErrs, field.Invalid(expPath.Child("endpoint"), exp.Endpoint, err.Error()))
335					}
336				}
337	
338				if exp.Interval != nil {
339					if err := validator.ValidateNginxDuration(string(*exp.Interval)); err != nil {
340						allErrs = append(allErrs, field.Invalid(expPath.Child("interval"), *exp.Interval, err.Error()))
341					}
342				}
343			}
344	
345			if telemetry.SpanAttributes != nil {
346				spanAttrPath := telPath.Child("spanAttributes")
347				for _, spanAttr := range telemetry.SpanAttributes {
348					if err := validator.ValidateEscapedStringNoVarExpansion(spanAttr.Key); err != nil {
349						allErrs = append(allErrs, field.Invalid(spanAttrPath.Child("key"), spanAttr.Key, err.Error()))
350					}
351	
352					if err := validator.ValidateEscapedStringNoVarExpansion(spanAttr.Value); err != nil {
353						allErrs = append(allErrs, field.Invalid(spanAttrPath.Child("value"), spanAttr.Value, err.Error()))
354					}
355				}
356			}
357		}
358	
359		if npCfg.Spec.IPFamily != nil {
360			ipFamily := npCfg.Spec.IPFamily
361			ipFamilyPath := spec.Child("ipFamily")
362			switch *ipFamily {
363			case ngfAPIv1alpha2.Dual, ngfAPIv1alpha2.IPv4, ngfAPIv1alpha2.IPv6:
364			default:
365				allErrs = append(
366					allErrs,
367					field.NotSupported(
368						ipFamilyPath,
369						ipFamily,
370						[]string{string(ngfAPIv1alpha2.Dual), string(ngfAPIv1alpha2.IPv4), string(ngfAPIv1alpha2.IPv6)}))
371			}
372		}
373	
374		allErrs = append(allErrs, validateLogging(validator, npCfg, plus)...)
375	
376		allErrs = append(allErrs, validateDNSResolver(validator, npCfg)...)
377	
378		allErrs = append(allErrs, validateRewriteClientIP(npCfg)...)
379	
380		allErrs = append(allErrs, validateNginxPlus(npCfg)...)
381	
382		allErrs = append(allErrs, validateServerTokens(validator, npCfg, plus)...)
383	
384		allErrs = append(allErrs, validateCompression(validator, npCfg)...)
385	
386		return allErrs
387	}
