389	func validateLogging(
390		validator validation.GenericValidator,
391		npCfg *ngfAPIv1alpha2.NginxProxy,
392		plus bool,
393	) field.ErrorList {
394		var allErrs field.ErrorList
395		spec := field.NewPath("spec")
396	
397		if npCfg.Spec.Logging != nil {
398			logging := npCfg.Spec.Logging
399			loggingPath := spec.Child("logging")
400	
401			if logging.ErrorLevel != nil {
402				errLevel := string(*logging.ErrorLevel)
403	
404				validLogLevels := []string{
405					string(ngfAPIv1alpha2.NginxLogLevelDebug),
406					string(ngfAPIv1alpha2.NginxLogLevelInfo),
407					string(ngfAPIv1alpha2.NginxLogLevelNotice),
408					string(ngfAPIv1alpha2.NginxLogLevelWarn),
409					string(ngfAPIv1alpha2.NginxLogLevelError),
410					string(ngfAPIv1alpha2.NginxLogLevelCrit),
411					string(ngfAPIv1alpha2.NginxLogLevelAlert),
412					string(ngfAPIv1alpha2.NginxLogLevelEmerg),
413				}
414	
415				if !slices.Contains(validLogLevels, errLevel) {
416					allErrs = append(
417						allErrs,
418						field.NotSupported(
419							loggingPath.Child("errorLevel"),
420							logging.ErrorLevel,
421							validLogLevels,
422						))
423				}
424			}
425	
426			if logging.ErrorLogFormat != nil && *logging.ErrorLogFormat == ngfAPIv1alpha2.NginxErrorLogFormatJSON && !plus {
427				allErrs = append(
428					allErrs,
429					field.Invalid(
430						loggingPath.Child("errorLogFormat"),
431						*logging.ErrorLogFormat,
432						"JSON-formatted error logs are only supported with NGINX Plus",
433					),
434				)
435			}
436	
437			if logging.AccessLog != nil && logging.AccessLog.Format != nil {
438				accessLogFormatPath := loggingPath.Child("accessLog", "format")
439				accessLogFormat := *logging.AccessLog.Format
440	
441				if err := validator.ValidateAccessLogFormatString(accessLogFormat); err != nil {
442					allErrs = append(
443						allErrs,
444						field.Invalid(
445							accessLogFormatPath,
446							accessLogFormat,
447							err.Error(),
448						),
449					)
450				}
451			}
452		}
453	
454		return allErrs
455	}
