457	func validateDNSResolver(
458		validator validation.GenericValidator,
459		npCfg *ngfAPIv1alpha2.NginxProxy,
460	) field.ErrorList {
461		if npCfg.Spec.DNSResolver == nil {
462			return nil
463		}
464	
465		var allErrs field.ErrorList
466		dnsResolver := npCfg.Spec.DNSResolver
467		dnsResolverPath := field.NewPath("spec", "dnsResolver")
468	
469		if dnsResolver.Timeout != nil {
470			if err := validator.ValidateNginxDuration(string(*dnsResolver.Timeout)); err != nil {
471				allErrs = append(allErrs, field.Invalid(
472					dnsResolverPath.Child("timeout"),
473					*dnsResolver.Timeout,
474					err.Error(),
475				))
476			}
477		}
478	
479		if dnsResolver.CacheTTL != nil {
480			if err := validator.ValidateNginxDuration(string(*dnsResolver.CacheTTL)); err != nil {
481				allErrs = append(allErrs, field.Invalid(
482					dnsResolverPath.Child("valid"),
483					*dnsResolver.CacheTTL,
484					err.Error(),
485				))
486			}
487		}
488	
489		addressesPath := dnsResolverPath.Child("addresses")
490		for i, addr := range dnsResolver.Addresses {
491			addrPath := addressesPath.Index(i)
492	
493			if addr.Type == ngfAPIv1alpha2.DNSResolverIPAddressType {
494				if errs := k8svalidation.IsValidIP(addrPath.Child("value"), addr.Value); len(errs) > 0 {
495					allErrs = append(allErrs, field.Invalid(
496						addrPath.Child("value"),
497						addr.Value,
498						"must be a valid IP address",
499					))
500				}
501			}
502	
503			if addr.Type == ngfAPIv1alpha2.DNSResolverHostnameType {
504				if errs := k8svalidation.IsDNS1123Subdomain(addr.Value); len(errs) > 0 {
505					for _, e := range errs {
506						allErrs = append(allErrs, field.Invalid(
507							addrPath.Child("value"),
508							addr.Value,
509							e,
510						))
511					}
512				}
513			}
514		}
515	
516		if len(dnsResolver.Addresses) == 0 {
517			allErrs = append(allErrs, field.Required(addressesPath, "addresses field is required"))
518		}
519	
520		return allErrs
521	}
522	
523	func validateRewriteClientIP(npCfg *ngfAPIv1alpha2.NginxProxy) field.ErrorList {
524		var allErrs field.ErrorList
525		spec := field.NewPath("spec")
526	
527		if npCfg.Spec.RewriteClientIP != nil {
528			rewriteClientIP := npCfg.Spec.RewriteClientIP
529			rewriteClientIPPath := spec.Child("rewriteClientIP")
530			trustedAddressesPath := rewriteClientIPPath.Child("trustedAddresses")
531	
532			if rewriteClientIP.Mode != nil {
533				mode := *rewriteClientIP.Mode
534				if len(rewriteClientIP.TrustedAddresses) == 0 {
535					allErrs = append(
536						allErrs,
537						field.Required(rewriteClientIPPath, "trustedAddresses field required when mode is set"),
538					)
539				}
540	
541				switch mode {
542				case ngfAPIv1alpha2.RewriteClientIPModeProxyProtocol, ngfAPIv1alpha2.RewriteClientIPModeXForwardedFor:
543				default:
544					allErrs = append(
545						allErrs,
546						field.NotSupported(
547							rewriteClientIPPath.Child("mode"),
548							mode,
549							[]string{
550								string(ngfAPIv1alpha2.RewriteClientIPModeProxyProtocol),
551								string(ngfAPIv1alpha2.RewriteClientIPModeXForwardedFor),
552							},
553						),
554					)
555				}
556			}
557	
558			if len(rewriteClientIP.TrustedAddresses) > 64 {
559				allErrs = append(
560					allErrs,
561					field.TooMany(trustedAddressesPath, len(rewriteClientIP.TrustedAddresses), 64),
562				)
563			}
564	
565			for _, addr := range rewriteClientIP.TrustedAddresses {
566				valuePath := trustedAddressesPath.Child("value")
567	
568				switch addr.Type {
569				case ngfAPIv1alpha2.RewriteClientIPCIDRAddressType:
570					if err := k8svalidation.IsValidCIDR(valuePath, addr.Value); err != nil {
571						allErrs = append(allErrs, err...)
572					}
573				case ngfAPIv1alpha2.RewriteClientIPIPAddressType:
574					if err := k8svalidation.IsValidIP(valuePath, addr.Value); err != nil {
575						allErrs = append(allErrs, err...)
576					}
577				case ngfAPIv1alpha2.RewriteClientIPHostnameAddressType:
578					if errs := k8svalidation.IsDNS1123Subdomain(addr.Value); len(errs) > 0 {
579						for _, e := range errs {
580							allErrs = append(allErrs, field.Invalid(valuePath, addr.Value, e))
581						}
582					}
583				default:
584					allErrs = append(
585						allErrs,
586						field.NotSupported(trustedAddressesPath.Child("type"),
587							addr.Type,
588							[]string{
589								string(ngfAPIv1alpha2.RewriteClientIPCIDRAddressType),
590								string(ngfAPIv1alpha2.RewriteClientIPIPAddressType),
591								string(ngfAPIv1alpha2.RewriteClientIPHostnameAddressType),
592							},
593						),
594					)
595				}
596			}
597		}
598	
599		return allErrs
600	}
601	
602	func validateNginxPlus(npCfg *ngfAPIv1alpha2.NginxProxy) field.ErrorList {
603		var allErrs field.ErrorList
604		spec := field.NewPath("spec")
605	
606		if npCfg.Spec.NginxPlus != nil {
607			nginxPlus := npCfg.Spec.NginxPlus
608			nginxPlusPath := spec.Child("nginxPlus")
609	
610			if nginxPlus.AllowedAddresses != nil {
611				for _, addr := range nginxPlus.AllowedAddresses {
612					valuePath := nginxPlusPath.Child("value")
613	
614					switch addr.Type {
615					case ngfAPIv1alpha2.NginxPlusAllowCIDRAddressType:
616						if err := k8svalidation.IsValidCIDR(valuePath, addr.Value); err != nil {
617							allErrs = append(allErrs, err...)
618						}
619					case ngfAPIv1alpha2.NginxPlusAllowIPAddressType:
620						if err := k8svalidation.IsValidIP(valuePath, addr.Value); err != nil {
621							allErrs = append(allErrs, err...)
622						}
623					default:
624						allErrs = append(
625							allErrs,
626							field.NotSupported(nginxPlusPath.Child("type"),
627								addr.Type,
628								[]string{
629									string(ngfAPIv1alpha2.NginxPlusAllowCIDRAddressType),
630									string(ngfAPIv1alpha2.NginxPlusAllowIPAddressType),
631								},
632							),
633						)
634					}
635				}
636			}
637		}
638	
639		return allErrs
640	}
641	
642	func validateServerTokens(
643		validator validation.GenericValidator,
644		npCfg *ngfAPIv1alpha2.NginxProxy,
645		plus bool,
646	) field.ErrorList {
647		if npCfg.Spec.ServerTokens == nil {
648			return nil
649		}
650	
651		var allErrs field.ErrorList
652		serverTokens := *npCfg.Spec.ServerTokens
653		serverTokensPath := field.NewPath("spec").Child("serverTokens")
654	
655		switch serverTokens {
656		case ServerTokenOff, ServerTokenOn, ServerTokenBuild:
657			// keywords are always valid for both OSS and Plus
658		default:
659			if !plus {
660				allErrs = append(
661					allErrs,
662					field.Invalid(
663						serverTokensPath,
664						serverTokens,
665						"custom string values for serverTokens are only allowed with NGINX Plus."+
666							" For NGINX OSS, allowed values are 'off', 'on', and 'build'.",
667					),
668				)
669			} else if err := validator.ValidateServerTokensValue(serverTokens); err != nil {
670				allErrs = append(
671					allErrs,
672					field.Invalid(serverTokensPath, serverTokens, err.Error()),
673				)
674			}
675		}
676		return allErrs
677	}
678	
679	func validateCompression(
680		validator validation.GenericValidator,
681		npCfg *ngfAPIv1alpha2.NginxProxy,
682	) field.ErrorList {
683		if npCfg.Spec.Compression == nil {
684			return nil
685		}
686	
687		var allErrs field.ErrorList
688		compressionPath := field.NewPath("spec").Child("compression")
689	
690		for i, mimeType := range npCfg.Spec.Compression.MimeTypes {
691			if !mimeTypePattern.MatchString(mimeType) {
692				allErrs = append(
693					allErrs,
694					field.Invalid(
695						compressionPath.Child("mimeTypes").Index(i),
696						mimeType,
697						"must be a valid MIME type with the form type/subtype",
698					),
699				)
700			}
701		}
702	
703		if npCfg.Spec.Compression.Gzip != nil {
704			gzipPath := compressionPath.Child("gzip")
705			for i, d := range npCfg.Spec.Compression.Gzip.Disable {
706				if err := validator.ValidateEscapedStringNoVarExpansion(d); err != nil {
707					allErrs = append(
708						allErrs,
709						field.Invalid(gzipPath.Child("disable").Index(i), d, err.Error()),
710					)
711				}
712			}
713	
714			validGzipProxied := []ngfAPIv1alpha2.GzipProxiedType{
715				ngfAPIv1alpha2.GzipProxiedOff,
716				ngfAPIv1alpha2.GzipProxiedExpired,
717				ngfAPIv1alpha2.GzipProxiedNoCache,
718				ngfAPIv1alpha2.GzipProxiedNoStore,
719				ngfAPIv1alpha2.GzipProxiedPrivate,
720				ngfAPIv1alpha2.GzipProxiedNoLastModified,
721				ngfAPIv1alpha2.GzipProxiedNoETag,
722				ngfAPIv1alpha2.GzipProxiedAuth,
723				ngfAPIv1alpha2.GzipProxiedAny,
724			}
725			for i, p := range npCfg.Spec.Compression.Gzip.Proxied {
726				if !slices.Contains(validGzipProxied, p) {
727					allErrs = append(
728						allErrs,
729						field.Invalid(
730							gzipPath.Child("proxied").Index(i),
731							p,
732							"invalid value; must be one of: off, expired, no-cache, no-store, private, no_last_modified, no_etag, auth, any",
733						),
734					)
735				}
736			}
737		}
738	
739		return allErrs
740	}
741

